+//! Progress bar renderable.
+//!
+//! This module provides progress bar components for displaying task progress
+//! in the terminal with various styles and features.
+
+use crate::cells;
+use crate::segment::Segment;
+use crate::style::Style;
+use crate::text::Text;
+use std::time::{Duration, Instant};
+
+/// Bar style variants for the progress bar.
+#[derive(Debug, Clone, Copy, PartialEq, Eq, Default)]
+pub enum BarStyle {
+    /// Standard ASCII bar using # and -
+    Ascii,
+    /// Unicode block characters (█▓░)
+    #[default]
+    Block,
+    /// Thin line style (─╸)
+    Line,
+    /// Dots style (●○)
+    Dots,
+    /// Shaded gradient style (█▇▆▅▄▃▂▁░)
+    Gradient,
+}
+
+impl BarStyle {
+    /// Get the completed character for this style.
+    #[must_use]
+    pub const fn completed_char(&self) -> &str {
+        match self {
+            Self::Ascii => "#",
+            Self::Block => "\u{2588}",   // █
+            Self::Line => "\u{2501}",    // ━
+            Self::Dots => "\u{25CF}",    // ●
+            Self::Gradient => "\u{2588}", // █
+        }
+    }
+
+    /// Get the remaining character for this style.
+    #[must_use]
+    pub const fn remaining_char(&self) -> &str {
+        match self {
+            Self::Ascii => "-",
+            Self::Block => "\u{2591}",   // ░
+            Self::Line => "\u{2500}",    // ─
+            Self::Dots => "\u{25CB}",    // ○
+            Self::Gradient => "\u{2591}", // ░
+        }
+    }
+
+    /// Get the pulse character for this style (edge of completion).
+    #[must_use]
+    pub const fn pulse_char(&self) -> &str {
+        match self {
+            Self::Ascii => ">",
+            Self::Block => "\u{2593}",   // ▓
+            Self::Line => "\u{257A}",    // ╺
+            Self::Dots => "\u{25CF}",    // ●
+            Self::Gradient => "\u{2593}", // ▓
+        }
+    }
+}
+
+/// Spinner animation frames.
+#[derive(Debug, Clone)]
+pub struct Spinner {
+    /// Animation frames.
+    frames: Vec<&'static str>,
+    /// Current frame index.
+    frame_index: usize,
+    /// Style for the spinner.
+    style: Style,
+}
+
+impl Default for Spinner {
+    fn default() -> Self {
+        Self::dots()
+    }
+}
+
+impl Spinner {
+    /// Create a dots spinner (⠋⠙⠹⠸⠼⠴⠦⠧⠇⠏).
+    #[must_use]
+    pub fn dots() -> Self {
+        Self {
+            frames: vec!["⠋", "⠙", "⠹", "⠸", "⠼", "⠴", "⠦", "⠧", "⠇", "⠏"],
+            frame_index: 0,
+            style: Style::new(),
+        }
+    }
+
+    /// Create a line spinner (⎺⎻⎼⎽⎼⎻).
+    #[must_use]
+    pub fn line() -> Self {
+        Self {
+            frames: vec!["⎺", "⎻", "⎼", "⎽", "⎼", "⎻"],
+            frame_index: 0,
+            style: Style::new(),
+        }
+    }
+
+    /// Create a simple spinner (|/-\).
+    #[must_use]
+    pub fn simple() -> Self {
+        Self {
+            frames: vec!["|", "/", "-", "\\"],
+            frame_index: 0,
+            style: Style::new(),
+        }
+    }
+
+    /// Create a bouncing ball spinner (⠁⠂⠄⠂).
+    #[must_use]
+    pub fn bounce() -> Self {
+        Self {
+            frames: vec!["⠁", "⠂", "⠄", "⠂"],
+            frame_index: 0,
+            style: Style::new(),
+        }
+    }
+
+    /// Create a growing dots spinner (⣾⣽⣻⢿⡿⣟⣯⣷).
+    #[must_use]
+    pub fn growing() -> Self {
+        Self {
+            frames: vec!["⣾", "⣽", "⣻", "⢿", "⡿", "⣟", "⣯", "⣷"],
+            frame_index: 0,
+            style: Style::new(),
+        }
+    }
+
+    /// Create a moon phase spinner (🌑🌒🌓🌔🌕🌖🌗🌘).
+    #[must_use]
+    pub fn moon() -> Self {
+        Self {
+            frames: vec!["🌑", "🌒", "🌓", "🌔", "🌕", "🌖", "🌗", "🌘"],
+            frame_index: 0,
+            style: Style::new(),
+        }
+    }
+
+    /// Create a clock spinner (🕐🕑🕒🕓🕔🕕🕖🕗🕘🕙🕚🕛).
+    #[must_use]
+    pub fn clock() -> Self {
+        Self {
+            frames: vec!["🕐", "🕑", "🕒", "🕓", "🕔", "🕕", "🕖", "🕗", "🕘", "🕙", "🕚", "🕛"],
+            frame_index: 0,
+            style: Style::new(),
+        }
+    }
+
+    /// Create a spinner from custom frames.
+    #[must_use]
+    pub fn custom(frames: Vec<&'static str>) -> Self {
+        Self {
+            frames,
+            frame_index: 0,
+            style: Style::new(),
+        }
+    }
+
+    /// Set the spinner style.
+    #[must_use]
+    pub fn style(mut self, style: Style) -> Self {
+        self.style = style;
+        self
+    }
+
+    /// Advance to the next frame and return the current frame.
+    pub fn next_frame(&mut self) -> &str {
+        if self.frames.is_empty() {
+            return " ";
+        }
+        let frame = self.frames[self.frame_index];
+        self.frame_index = (self.frame_index + 1) % self.frames.len();
+        frame
+    }
+
+    /// Get the current frame without advancing.
+    #[must_use]
+    pub fn current_frame(&self) -> &str {
+        if self.frames.is_empty() {
+            return " ";
+        }
+        self.frames[self.frame_index]
+    }
+
+    /// Render the current spinner frame as a segment.
+    #[must_use]
+    pub fn render(&self) -> Segment {
+        Segment::new(self.current_frame(), Some(self.style.clone()))
+    }
+}
